'use client'

import { Suspense, useState, useEffect } from "react"
import { useParams, useRouter } from "next/navigation"
import MatchPlayer from "@/components/match/match-player"
import MatchInfo from "@/components/match/match-info" 
import { 
  ArrowLeft, 
  Minimize, 
  Share2, 
  Copy, 
  MessageSquare, 
  AlertTriangle,
  CheckCircle,
  Twitter,
  Facebook,
  Tv
} from "lucide-react"
import "@/styles/match.css"
import { useLanguage } from "@/context/language-context"

// 🔥 RESPONSIVE CSS ENGINE
const pageStyles = `
  /* BASE RESET */
  .match-page-container {
    min-height: 100vh;
    width: 100%;
    background: #050505;
    padding-bottom: 40px;
    overflow-x: hidden; /* CRITICAL: Stops horizontal scroll */
  }

  /* TOP BAR */
  .top-nav {
    max-width: 1600px;
    margin: 0 auto;
    padding: 15px 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 1px solid rgba(255,255,255,0.05);
  }

  /* GRID SYSTEM */
  .match-grid {
    display: grid;
    gap: 20px;
    max-width: 1600px;
    margin: 0 auto;
    padding: 20px;
    width: 100%;
    box-sizing: border-box; /* Ensures padding doesn't add to width */
  }

  /* DESKTOP LAYOUT */
  .layout-standard {
    grid-template-columns: 1fr 340px;
  }
  .layout-cinema {
    grid-template-columns: 1fr;
    max-width: 1200px; /* Cinema mode focus */
  }

  /* PLAYER WRAPPER */
  .player-wrapper {
    width: 100%;
    background: #000;
    aspect-ratio: 16/9;
    position: relative;
    box-shadow: 0 10px 30px rgba(0,0,0,0.5);
    /* SHARP EDGES - YOUTUBE STYLE */
    border: none; 
  }

  /* MATCH TITLE (CLEAN) */
  .match-main-title {
    color: #fff;
    font-size: 18px;
    font-weight: 800;
    margin-bottom: 12px;
    line-height: 1.2;
    display: flex;
    align-items: center;
    gap: 10px;
  }
  .live-tag {
    background: #8db902;
    color: #000;
    font-size: 10px;
    font-weight: 900;
    padding: 2px 6px;
    border-radius: 2px;
    text-transform: uppercase;
  }

  /* CHAT PANEL */
  .chat-panel {
    background: #0a0a0a;
    border: 1px solid #1a1a1a;
    display: flex;
    flex-direction: column;
    height: 600px;
    overflow: hidden;
  }

  /* MOBILE RESPONSIVE OVERRIDES */
  @media (max-width: 1024px) {
    .match-grid {
      grid-template-columns: 100%; /* Force single column */
      padding: 0; /* Remove padding to go edge-to-edge on mobile */
      gap: 0;
    }
    
    .top-nav {
      padding: 12px 15px;
    }

    .player-section {
      width: 100%;
    }

    /* Player goes full width on mobile */
    .player-wrapper {
      width: 100vw; 
      max-width: 100%;
    }

    /* Controls padding fix */
    .controls-bar, .match-main-title {
      padding-left: 15px;
      padding-right: 15px;
    }

    /* Chat moves below */
    .chat-panel {
      height: 500px;
      margin-top: 10px;
      border-radius: 0; /* Full width chat */
      border-left: none;
      border-right: none;
    }
  }
`

function MatchPageContent() {
  const router = useRouter()
  const params = useParams()
  const matchId = String(params.id)
  const { t } = useLanguage()

  // --- STATES ---
  const [cinemaMode, setCinemaMode] = useState(false)
  const [chatAgreed, setChatAgreed] = useState(false)
  const [showEmbed, setShowEmbed] = useState(false)
  const [copied, setCopied] = useState(false)
  
  // 🔥 FETCH TITLE LOGIC
  const [matchTitle, setMatchTitle] = useState("Loading Stream...")
  
  useEffect(() => {
    // Try to get match data from session storage to avoid a flicker
    const stored = sessionStorage.getItem("currentMatch")
    if (stored) {
      try {
        const data = JSON.parse(stored)
        // Prefer Title, then Competition, then Names
        const displayTitle = data.title || data.competition || `${data.teams?.home?.name || 'Home'} vs ${data.teams?.away?.name || 'Away'}`
        setMatchTitle(displayTitle)
      } catch (e) {
        setMatchTitle("Live Stream")
      }
    }
  }, [])

  const embedCode = `<iframe src="https://reedstreams.com/embed/${matchId}" width="100%" height="500" frameborder="0" allowfullscreen></iframe>`

  const handleCopy = () => {
    navigator.clipboard.writeText(embedCode)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  return (
    <>
      <style jsx global>{pageStyles}</style>
      
      <div className="match-page-container" style={{ background: cinemaMode ? '#000' : '#050505' }}>
        
        {/* 1. TOP NAV BAR */}
        {!cinemaMode && (
          <div className="top-nav">
            <div style={{display:'flex', alignItems:'center', gap:'15px'}}>
              {/* BRAND LOGO */}
              <div style={{fontSize:'20px', fontWeight:900, letterSpacing:'-1px', fontFamily:'sans-serif'}}>
                <span style={{color:'#fff'}}>REED</span>
                <span style={{color:'#8db902'}}>STREAMS</span>
              </div>
              
              <div style={{width:'1px', height:'20px', background:'#333'}}></div>
              
              <button 
                  onClick={() => router.back()} 
                  style={{background:'none', border:'none', color:'#888', cursor:'pointer', display:'flex', alignItems:'center', gap:'6px', fontSize:'11px', fontWeight:700, textTransform:'uppercase'}}
              >
                  <ArrowLeft size={14} /> {t.back_to_home || "Back"}
              </button>
            </div>
            {/* Right side empty (Clean look) */}
            <div></div>
          </div>
        )}

        {/* 🔥 THE MAIN GRID */}
        <div className={`match-grid ${cinemaMode ? 'layout-cinema' : 'layout-standard'}`}>
          
          {/* === LEFT: PLAYER & INFO === */}
          <div className="player-section">
              
              {/* 🏆 CLEAN MATCH TITLE (Desktop/Mobile) */}
              {!cinemaMode && (
                <div className="match-main-title">
                  <span className="live-tag">LIVE</span>
                  <span>{matchTitle}</span>
                </div>
              )}

              {/* 🎥 THE VIDEO PLAYER (Full Width, Sharp Edges) */}
              <div className="player-wrapper">
                <MatchPlayer matchId={matchId} />
              </div>

              {/* 🎛️ CONTROLS BAR */}
              <div className="controls-bar" style={{
                marginTop:'12px', 
                display:'flex',
                justifyContent:'space-between',
                alignItems:'center',
                flexWrap:'wrap',
                gap:'10px'
              }}>
                
                {/* Cinema Toggle */}
                <button 
                  className={`action-btn ${cinemaMode ? 'active' : ''}`}
                  onClick={() => setCinemaMode(!cinemaMode)}
                  style={{
                    background: '#111', border: '1px solid #222', color: '#ccc',
                    padding: '8px 12px', borderRadius: '4px', fontSize: '11px', fontWeight: 700,
                    cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px', textTransform: 'uppercase'
                  }}
                >
                  {cinemaMode ? <Minimize size={14}/> : <Tv size={14}/>}
                  {cinemaMode ? "Exit Cinema" : "Cinema Mode"}
                </button>

                {/* Tools (Share/Embed) */}
                {!cinemaMode && (
                  <div style={{display:'flex', gap:'8px', alignItems:'center'}}>
                    <div style={{display:'flex', gap:'4px', paddingRight:'10px', borderRight:'1px solid #222'}}>
                      <button style={{background:'#111', border:'1px solid #222', color:'#888', padding:'6px', borderRadius:'4px', cursor:'pointer'}}><Twitter size={14} /></button>
                      <button style={{background:'#111', border:'1px solid #222', color:'#888', padding:'6px', borderRadius:'4px', cursor:'pointer'}}><Facebook size={14} /></button>
                      <button style={{background:'#111', border:'1px solid #222', color:'#888', padding:'6px', borderRadius:'4px', cursor:'pointer'}}><MessageSquare size={14} /></button>
                    </div>

                    <button 
                      onClick={() => setShowEmbed(!showEmbed)}
                      style={{
                        background: '#111', border: '1px solid #222', color: '#ccc',
                        padding: '8px 12px', borderRadius: '4px', fontSize: '11px', fontWeight: 700,
                        cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px', textTransform: 'uppercase'
                      }}
                    >
                      <Share2 size={14} /> Embed
                    </button>
                  </div>
                )}
              </div>

              {/* 📜 EMBED BOX */}
              {showEmbed && !cinemaMode && (
                <div className="controls-bar" style={{marginTop:'10px'}}>
                  <div style={{background:'#000', padding:'12px', borderRadius:'4px', border:'1px solid #222', display:'flex', gap:'10px'}}>
                    <input 
                      readOnly 
                      value={embedCode} 
                      style={{background:'transparent', border:'none', color:'#888', width:'100%', fontSize:'11px', fontFamily:'monospace', outline:'none'}} 
                    />
                    <button onClick={handleCopy} style={{background:'transparent', border:'none', cursor:'pointer', color: copied ? '#8db902' : '#fff'}}>
                      {copied ? <CheckCircle size={16} /> : <Copy size={16} />}
                    </button>
                  </div>
                </div>
              )}
          </div>

          {/* === RIGHT: CHAT SECTION === */}
          {!cinemaMode && (
            <div className="chat-panel">
                
                {/* CHAT HEADER */}
                <div style={{padding:'12px 15px', borderBottom:'1px solid #222', display:'flex', justifyContent:'space-between', alignItems:'center', background:'#0f0f0f'}}>
                    <span style={{color:'#fff', fontWeight:'bold', fontSize:'13px'}}>Live Chat</span>
                    <div style={{display:'flex', alignItems:'center', gap:'6px', fontSize:'11px', color:'#888'}}>
                      <div style={{width:'6px', height:'6px', background:'#8db902', borderRadius:'50%'}}></div> 
                      1.2k
                    </div>
                </div>
                
                {/* CHAT CONTENT */}
                <div style={{flex:1, position:'relative', background:'#050505'}}>
                  
                  {/* 🔒 "GOOD BOY" BLUR OVERLAY */}
                  {!chatAgreed && (
                    <div style={{
                      position:'absolute', top:0, left:0, width:'100%', height:'100%', 
                      background:'rgba(5,5,5,0.9)', backdropFilter:'blur(4px)', zIndex:10,
                      display:'flex', flexDirection:'column', justifyContent:'center', alignItems:'center', padding:'20px', textAlign:'center'
                    }}>
                      <AlertTriangle size={28} color="#8db902" style={{marginBottom:'10px'}} />
                      <h3 style={{color:'#fff', fontSize:'14px', fontWeight:'800', margin:'0 0 5px 0'}}>Chat Rules</h3>
                      <p style={{color:'#888', fontSize:'11px', lineHeight:'1.4', marginBottom:'15px', maxWidth:'180px'}}>
                        Be respectful. No hate speech. No spamming.
                      </p>
                      <button 
                        onClick={() => setChatAgreed(true)}
                        style={{
                          background:'#8db902', color:'#000', border:'none', padding:'8px 24px', 
                          borderRadius:'4px', fontSize:'11px', fontWeight:'800', cursor:'pointer',
                          textTransform:'uppercase'
                        }}
                      >
                        I Agree
                      </button>
                    </div>
                  )}

                  {/* 💬 PLACEHOLDER MESSAGES */}
                  <div className="chat-messages" style={{padding:'15px', height:'100%', overflowY:'auto'}}>
                    <div style={{color:'#444', fontSize:'11px', marginBottom:'10px', textAlign:'center', borderBottom:'1px solid #111', paddingBottom:'10px'}}>
                      Welcome to the chat room.
                    </div>
                    {[1,2,3,4,5].map((i) => (
                       <div key={i} style={{marginBottom:'8px', fontSize:'12px', display:'flex', gap:'8px'}}>
                         <span style={{color: i%2===0 ? '#8db902' : '#4a9eff', fontWeight:'bold', fontSize:'11px'}}>User{i*99}:</span>
                         <span style={{color:'#ccc'}}>Stream looks clean today</span>
                       </div>
                    ))}
                  </div>

                </div>

                {/* INPUT AREA */}
                <div style={{padding:'12px', borderTop:'1px solid #222', background:'#0f0f0f'}}>
                    <input 
                      type="text" 
                      placeholder={chatAgreed ? "Type a message..." : "Agree to rules first"} 
                      disabled={!chatAgreed}
                      style={{
                        width:'100%', background:'#050505', border:'1px solid #222', 
                        padding:'10px 12px', borderRadius:'4px', color:'#fff', fontSize:'12px', outline:'none'
                      }} 
                    />
                </div>
            </div>
          )}

        </div>
      </div>
    </>
  )
}

export default function MatchPage() {
  return (
    <Suspense fallback={<div style={{color:'#444', textAlign:'center', marginTop:'50px'}}>Loading Arena...</div>}>
        <MatchPageContent />
    </Suspense>
  )
}